import{_ as a,o as t,c as b,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"祖国人","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/祖国人.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/祖国人.md"}'),s={name:"4.资源分区/1.血统与训练/6.一次性血统/祖国人.md"};function o(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"祖国人",tabindex:"-1"},[p("祖国人 "),r("a",{class:"header-anchor",href:"#祖国人","aria-label":'Permalink to "祖国人"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调017")])])],-1),n('<h1 id="祖国人-1" tabindex="-1">祖国人 <a class="header-anchor" href="#祖国人-1" aria-label="Permalink to &quot;祖国人&quot;">​</a></h1><p>祖国人<br> 价格：B+2500<br> 描述：描述：在美漫IP《黑袍纠察队》世界观中，沃特公司利用“五号化合物”制造出了在公众视野中活动的超级英雄，并以此来笼络人心和牟取暴利。其中最为强大，也最为知名的超级英雄，就是身披星条旗披风的“Homelander”，也就是祖国人。<br> 祖国人的能力近似于DC漫画中所描绘的超人，但是由于是纯粹的人类科技通过化合物在实验室下催化的产物，因而也具有其局限性。</p><p>【超人身躯】：<br> “我的体表是防弹的。但是体内……这颗心，它并不防弹，和你们一样，我也是人。”美国人民敬仰的超级英雄祖国人曾经如此说过。我们先不论后半句的真实性，起码前半句是货真价实的。<br> 祖国人的身体具有惊人的耐性和强度，足够抵抗地球上绝大多数现存武器的进攻。因此祖国人具有12点天生防御，并且具有基于该天生防御的【防弹】。<br> 并且人类现有的绝大多数的爆炸类武器，也无法伤害到祖国人，因此祖国人还具有防御上的【适应】和【超级坚韧】。</p><p>【超人飞行】：祖国人和绝大多数类似于超人的角色一样，具有飞行的能力，因此祖国人还具有良好飞行能力。此外，祖国人能够飞行至太空之中俯瞰整个纽约的夜景，因此祖国人还具有【三防】能力，能够凭借飞行在大气层外活动。</p><p>血统下属能力：</p><p>超人力量<br> 价格：C+1000<br> 描述：作为美国人的超级英雄，祖国人可以采取一些非常手段为美国人民解除一些麻烦，比如直接干脆把劫匪丢到天上，或者是不小心把恐怖分子的整个身体直接打穿之类的，这都依赖于祖国人的超人力量。<br> 不过这种能力偶尔也会带来小麻烦，比如“不小心”把自己的同伴双峰贯耳之类的，不过相信，应该没人会对最伟大的超级英雄祖国人有意见的。<br> 因为祖国人的超人力量，你现在在以力量进行的检定上获得2点附加成功，并且现在你以力量进行的攻击检定上还会附带C级的【击飞】效果。</p><p>超人感官<br> 价格：C+1000<br> 描述：祖国人具有非常敏感的听觉与嗅觉，所以他能够细致地了解自己的同伴的想法，所以拥有这么一位“善解人意”的领袖，对于七人组来说，真可谓是天赐英杰。<br> 当然，也因为如此，没有“必要”在背后说祖国人的坏话，或者说是在心底悄悄对祖国人的出现感到焦虑，这一切都逃不过祖国人的感知，祖国人在发现之后，一定会好好地关怀他的同伴。<br> 因为祖国人的超人感官，你现在的听觉变为【强感知】，这意味着你可以隔着一定的阻碍听到他人谈话的声<br> 声音，并且你在基于感知的检定上获得1点附加成功。<br> 同时，祖国人现在可以通过听觉对于心跳声音和呼吸节奏的敏感以及嗅觉对于人体内分泌的改变的导致的体味变化的感知来判断一个人的情绪状态。可以在经过对抗后，获取针对多种固定类型的心理活动或情绪，无法读取具体想法，可读取目标是否说谎。<br> 这视为你具有创伤来源的C级读心效果，</p><p>热能镭射眼<br> 价格：B+2000<br> 描述：祖国人最为招牌的能力之一，从眼部射出具有致命高温的红色激光，具有非常强大的杀伤力。<br> 这个能力会占据你的瞳术位。你可以以一个标准动作进行一次攻击，在这次攻击中，你以耐力属性+射击+专业：眼部射线+专业：能量爆发来决定DP，被攻击分目标以反射豁免伤害。<br> 在这次攻击上，你还额外具有12L武器伤害和100米的射程。<br> 由于祖国人可以在射穿一个恐怖分子后，还可以给恐怖分子身后的孩童亲切地送去温暖，所以这次攻击还具有【贯穿】特性。<br> 从眼部射出的光线的速度奇快无比，具有B级别的【先制】。<br> 因为祖国人的眼部射线可以轻松地如同切开黄油一般切开飞机，并且起码在祖国人自己的脑补中可以如同收割倒下的麦穗一样收割眼前的人群，因而这次攻击还可以变为以射程的一半为半径的圆为范围的范围攻击。<br> 并且由于祖国人眼部激光所具有的恐怖热能，祖国人可以做到把枪械烧熔，并且让枪械和劫匪的手部亲密贴合的事情，所以这次攻击还会附带有等同于伤害点数的燃烧点数。</p><p>公司包装<br> 价格：B+2000<br> 描述：现在你获得了祖国人某种意义上最为强大的能力——被包装好的英雄身份。<br> 这意味着你每去到一个影片世界之后，都会有一个庞大的势力将你作为推出台前的代表形象，并且你会在这个世界当中受到大众的广泛敬仰和爱戴，群众会自发地认为你是一个伟大的英雄角色。<br> 当然，只是大多数时候这么认为，实际上ST为你所安排的背后势力应当只是为了以你的影响力牟取利益的存在，为了符合原著，这个势力应当体现出资本原始而野蛮的逐利性，当然是否与这个势力完全合作还是由你的意思决定，毕竟祖国人也和沃特公司闹掰了。<br> 在具有美国存在的世界观当中，你所背靠的这个势力应尽可能是美国和美国所属的某个巨大的私立资本公司（例如去到漫威世界中，可能就是史塔克的军工资本，或者说是奥斯本工业对你进行扶持，）如果不存在美国，可以尽量选择与美国意象相近的势力（例如去到地狱潜兵世界，可能就会成为超级地球人尽皆知的大英雄），如果去到东方类世界观，则可能是某些大宗门，或者朝廷，扶持出来的鹰犬头目。（例如六扇门总捕头之类的）。<br> 这是一个A级别的命运来源的背景身份能力，购买这个能力不会获得自由属性。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
